INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('blood-thinner-dental', '항응고제와 치과 치료', 'Blood Thinners and Dental Treatment', '일반', '혈액 희석제 복용 환자의 치과 치료 주의사항', '와파린, 아스피린 등 항응고제를 복용하는 환자는 발치나 수술 시 출혈 위험이 높습니다. 사전에 의사와 상의하여 약물 조절 후 치료를 진행해야 합니다.', NULL, '발치,출혈,지혈', 2, 0),
('pregnancy-dental', '임산부 치과 치료', 'Dental Care During Pregnancy', '일반', '임신 중 치과 치료 가능 여부와 주의사항', '임신 중에도 치과 치료가 가능하며, 특히 임신성 치은염 관리가 중요합니다. 임신 4~6개월이 가장 안전한 치료 시기이며, 방사선 촬영은 최소화합니다.', NULL, '잇몸,임신,예방', 1, 0),
('enamel-microabrasion', '법랑질 미세삭제술', 'Enamel Microabrasion', '보철', '법랑질 표면의 변색을 제거하는 시술', '치아 표면의 갈색/흰색 반점이나 얼룩을 미세하게 삭제하여 제거하는 최소 침습 심미 시술입니다. 미백으로 해결되지 않는 법랑질 변색에 효과적입니다.', 'cosmetic', '미백,법랑질,심미', 2, 0),
('dental-dam', '러버댐', 'Dental Dam (Rubber Dam)', '장비', '치료 부위를 격리하는 고무 방수막', '신경치료나 레진 충전 시 치료하는 치아만 노출시키고 나머지를 고무막으로 덮어 타액과 세균을 차단하는 장비입니다. 치료 정확도와 안전성을 높입니다.', NULL, '신경치료,레진,감염 관리', 1, 0),
('dental-x-ray-safety', '치과 X선 안전성', 'Dental X-ray Safety', '장비', '치과 방사선 촬영의 안전성', '치과 X선의 방사선량은 매우 낮아(파노라마 1장 ≈ 0.01mSv) 비행기 탑승이나 일상 자연방사선보다 적습니다. 납 앞치마 착용으로 추가 보호합니다.', NULL, 'X-ray,파노라마,안전', 1, 0),
('oral-cancer-screening', '구강암 검진', 'Oral Cancer Screening', '외과', '구강암의 조기 발견을 위한 검사', '혀, 잇몸, 입천장, 볼 점막 등의 이상 소견(궤양, 백반증, 홍반증, 종괴 등)을 시진과 촉진으로 확인합니다. 조기 발견 시 생존율이 크게 높아집니다.', NULL, '조직 검사,구강 점막,예방', 2, 0),
('stomatitis', '구내염', 'Stomatitis', '외과', '입안 점막에 생기는 염증성 궤양', '입안 점막에 발생하는 통증이 있는 작은 궤양입니다. 스트레스, 면역력 저하, 비타민 결핍, 외상 등이 원인이며, 대부분 1~2주 내에 자연 치유됩니다.', NULL, '구강 점막,통증,면역', 1, 0),
('plaque', '치태 (플라그)', 'Dental Plaque', '치주', '치아 표면에 형성되는 세균막', '치아 표면에 형성되는 무색의 끈적한 세균 막으로, 양치의 주요 제거 대상입니다. 제거하지 않으면 48시간 내 치석으로 경화되며, 충치와 잇몸병의 근본 원인입니다.', NULL, '치석,잇몸,충치', 1, 0),
('calculus', '치석', 'Dental Calculus (Tartar)', '치주', '치태가 석회화되어 딱딱해진 침착물', '치태가 타액의 칼슘, 인 등 미네랄과 결합하여 딱딱하게 굳은 것입니다. 칫솔질로는 제거가 불가능하며, 치과에서 스케일링으로 제거해야 합니다.', 'scaling', '치태,스케일링,잇몸', 1, 0),
('waterpik', '구강 세정기 (워터픽)', 'Water Flosser', '소아', '물줄기로 치아 사이를 청소하는 장치', '고압 물줄기를 분사하여 치아 사이와 잇몸 라인의 음식물과 세균을 제거하는 장치입니다. 임플란트, 교정 장치, 브릿지 주변 청소에 특히 유용합니다.', NULL, '임플란트,교정,잇몸', 1, 0),
('mouthguard', '스포츠 마우스가드', 'Sports Mouthguard', '소아', '운동 시 치아를 보호하는 장치', '축구, 농구, 격투기 등 접촉성 운동 시 치아 파절, 탈구, 턱 골절 등을 예방하기 위해 착용하는 보호 장치입니다. 맞춤 제작형이 기성품보다 효과적입니다.', NULL, '치아 보호,외상,스포츠', 1, 0),
('interdental-brush', '치간 칫솔', 'Interdental Brush', '치주', '치아 사이를 청소하는 작은 솔', '치아와 치아 사이 공간을 닦기 위한 작은 원통형 솔입니다. 일반 칫솔이 닿지 않는 치간 부위의 치태 제거에 효과적이며, 잇몸 건강 유지에 필수적입니다.', NULL, '치태,잇몸,구강위생', 1, 0),
('dental-floss', '치실', 'Dental Floss', '치주', '치아 사이를 청소하는 실', '얇은 실을 치아 사이에 넣어 칫솔이 닿지 않는 인접면의 치태와 음식 찌꺼기를 제거합니다. 하루 1회 사용을 권장하며, 충치와 잇몸병 예방에 효과적입니다.', NULL, '치태,충치,잇몸', 1, 0),
('tongue-cleaning', '혀 닦기', 'Tongue Cleaning', '일반', '혀 표면의 세균과 설태를 제거하는 구강 관리', '혀 표면에 쌓이는 백태(설태)는 구취의 주요 원인입니다. 전용 혀 클리너나 칫솔 뒷면으로 혀를 닦으면 구취 감소에 큰 효과가 있습니다.', NULL, '구취,설태,구강위생', 1, 0),
('bisphosphonate', '비스포스포네이트', 'Bisphosphonate', '보험', '골다공증 치료약과 턱뼈 괴사 위험', '골다공증 치료에 사용되는 약물로, 장기간 복용 시 턱뼈 괴사(MRONJ) 위험이 있습니다. 발치나 임플란트 수술 전 반드시 복용 이력을 의사에게 알려야 합니다.', NULL, '골다공증,임플란트,턱뼈 괴사', 2, 0);
